package com.welltrack.identity.service; import lombok.*; import org.springframework.stereotype.Service; import java.util.*; import org.springframework.security.crypto.password.*; import com.welltrack.identity.repository.*; import com.welltrack.identity.entity.*; @Service @RequiredArgsConstructor public class UserService{ private final UserRepository repo; private final PasswordEncoder enc; private final AuditService audit; public User createUser(User u){u.setPassword(enc.encode(u.getPassword()));u.setStatus("ACTIVE");User s=repo.save(u);audit.log(s.getUserId(),"CREATE","USER");return s;} public List<User> all(){return repo.findAll();}}